+    #[test]
+    fn handle_auth_required_metadata() {
+        let workflow = HandleAuthRequired::new();
+        assert_eq!(workflow.name(), "handle_auth_required");
+        assert_eq!(
+            workflow.description(),
+            "Centralize auth-required events with strategy selection and cooldown"
+        );
